const raw = $json.stdout || $json.data || $json.response || '';
const now = new Date().toISOString();
const files = raw.split('\n').map(s => s.trim()).filter(s => s.endsWith('.md'));
const healthy = files.length > 0;
const blocks = [ { type: 'header', text: { type: 'plain_text', text: '🪄 Memory Maintenance' } }, { type: 'context', elements: [ { type: 'mrkdwn', text: `*Checked:* ${now}` }, { type: 'mrkdwn', text: `*Recent Files:* ${files.length}` } ] }, { type: 'divider' }, { type: 'section', text: { type: 'mrkdwn', text: files.length ? `*Recent memory files*\n• ${files.slice(0, 12).join('\n• ')}` : 'No memory files found.' } } ];
return [{ json: { checkedAt: now, healthy, slackText: `🪄 Memory maintenance: ${files.length} file(s)`, slackBlocks: blocks } }];
